from pybricks.hubs import PrimeHub
from pybricks.parameters import Axis, Direction, Port, Stop
from pybricks.pupdevices import Motor
from pybricks.robotics import DriveBase
from pybricks.tools import StopWatch, multitask, run_task, wait

from utility import compensate_backlash, steer_turn

# Set up all devices.
prime_hub = PrimeHub(top_side=Axis.Z, front_side=Axis.X)
watch = StopWatch()
leftwheel = Motor(Port.D, Direction.COUNTERCLOCKWISE)
rightwheel = Motor(Port.C, Direction.CLOCKWISE)
leftattachment = Motor(Port.B, Direction.CLOCKWISE)
rightattachment = Motor(Port.F, Direction.COUNTERCLOCKWISE)
drive_base = DriveBase(leftwheel, rightwheel, 62.4, 80)

async def subtask():
    drive_base.settings(straight_speed=600)
    drive_base.settings(straight_acceleration=300)
    drive_base.settings(turn_rate=180)
    drive_base.settings(turn_acceleration=200)
    await drive_base.straight(-10)
    drive_base.reset(0, 0)
    await drive_base.straight(710)

async def subtask2():
    await leftattachment.run_until_stalled(-500, Stop.HOLD, 30)
    leftattachment.reset_angle(0)
    await leftattachment.run_angle(500, 30)

async def subtask3():
    await rightattachment.run_until_stalled(-500, Stop.HOLD, 50)
    rightattachment.reset_angle(0)
    await rightattachment.run_target(500, 150)

async def main():
    print('battery', prime_hub.battery.voltage())
    drive_base.use_gyro(True)
    await multitask(
        subtask(),
        subtask2(),
        subtask3(),
    )
    # Facing mission 02
    await multitask(
        drive_base.turn(-50),
        rightattachment.run_target(500, 80),
    )
    await drive_base.turn(5)
    await drive_base.straight(20)
    # Lift right arm, clear top soil
    await rightattachment.run_target(250, 200)
    await drive_base.straight(150)
    await drive_base.straight(-110)
    await steer_turn(drive_base, leftwheel, rightwheel, -90, False)
    await wait(100)
    # Lift left arm, pick up brush
    await drive_base.straight(90)
    await leftattachment.run_angle(500, 200)
    # Back to home
    drive_base.settings(straight_speed=600)
    drive_base.settings(straight_acceleration=600)
    await drive_base.arc(-120, distance=-180, then=Stop.NONE)
    await drive_base.straight(-600)
    print('Mapreveal time', watch.time(), sep=",")


run_task(main())